#### Solutions: ```typescript
interface Type<T> {
    tag: string;
    type: T;
}
interface DiscriminatedUnion<T> {
    [tag: string]: Type<T>;
}
function parseUnion(s: string): DiscriminatedUnion<string> {
    const pairs = s.split('|');
    const result: DiscriminatedUnion<string> = {};

    pairs.forEach(pair => {
        const [tag, types] = pair.split('(');
        const tags = tag.trim().split(',');
        const typesList = types.replace(')', '').split('|');
        tags.forEach((tag, index) => {
            result[tag.trim()] = {
                tag,
                type: typesList[index].trim()
            };
        });
    });

    return result;
}
console.log(parseUnion('tag1|tag2(tag1|tag2)));
```
